        if (current.size() == k) {
            if (n == 0) {
                result.push_back(current);
            }
            return;
        }
        for (int i = start; i <= 9; i++) {
            if (n - i >= 0) {
                current.push_back(i);
                backtrack(i + 1, k, n - i);
                current.pop_back();
            }
        }
