class Solution:
    def combinationSum3(self, k: int, n: int) -> List[List[int]]:
        def backtrack(start: int, current: List[int], remaining_sum: int) -> None:
            if len(current) == k:
                if remaining_sum == 0:
                    result.append(current[:])
                return
            for i in range(start, 10):
                if remaining_sum - i >= 0:
                    current.append(i)
                    backtrack(i + 1, current, remaining_sum - i)
                    current.pop()
        result: List[List[int]] = []
        backtrack(1, [], n)
        return result

