#include <numeric>

#include <iostream>
#include <vector>

using namespace std;

class Solution {
public:
    vector<vector<int>> combinationSum3(int k, int n) {
        vector<vector<int>> result;
        vector<int> path;
        backtrack(result, path, k, n, 1);
        return result;
    }

    void backtrack(vector<vector<int>>& result, vector<int>& path, int k, int target, int start) {
        if (path.size() == k) {
            if (target == 0) {
                result.push_back(path);
            }
            return;
        }
        for (int i = start; i <= 9; i++) {
            if (i <= target) {
                path.push_back(i);
                backtrack(result, path, k, target - i, i + 1);
                path.pop_back();
            }
        }
    }
};

int main() {
    int k, n;
    cin >> k >> n;
    Solution sol;
    vector<vector<int>> ans = sol.combinationSum3(k, n);
    if (ans.empty()) {
        cout << -1 << endl;
    } else {
        for (const auto& combination : ans) {
            for (int i = 0; i < combination.size(); i++) {
                cout << combination[i] << (i == combination.size() - 1 ? "" : " ");
            }
            cout << endl;
        }
    }
    return 0;
}
